from typing import List, Dict, Any
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine


def _results_to_dicts(search_results: List[SearchResult]) -> List[Dict[str, Any]]:
    """Convert SearchResult objects to dictionaries expected by MetadataFilterEngine."""
    result_dicts: List[Dict[str, Any]] = []
    for result in search_results:
        # This mirrors how the core library converts SearchResult -> dict
        result_dicts.append(
            {
                "id": getattr(result, "id", None),
                "score": getattr(result, "score", None),
                "text": getattr(result, "text", None),
                "metadata": getattr(result, "metadata", None),
            }
        )
    return result_dicts


def _dicts_to_results(
    original_results: List[SearchResult],
    filtered_dicts: List[Dict[str, Any]],
) -> List[SearchResult]:
    """
    Convert filtered result dictionaries back to SearchResult objects, preserving
    the original object instances and their structure.
    """
    # Build a map from id to original SearchResult for quick lookup.
    # If ids are not unique or missing, fall back to positional matching.
    id_to_result = {}
    for res in original_results:
        res_id = getattr(res, "id", None)
        if res_id is not None and res_id not in id_to_result:
            id_to_result[res_id] = res

    filtered_results: List[SearchResult] = []
    used_indices = set()

    for fd in filtered_dicts:
        fd_id = fd.get("id", None)
        match: SearchResult | None = None

        if fd_id is not None and fd_id in id_to_result:
            match = id_to_result[fd_id]
        else:
            # Fallback: match by first unused position
            for idx, res in enumerate(original_results):
                if idx in used_indices:
                    continue
                # Best-effort structural match on text/metadata/score
                if (
                    getattr(res, "text", None) == fd.get("text")
                    and getattr(res, "metadata", None) == fd.get("metadata")
                    and getattr(res, "score", None) == fd.get("score")
                ):
                    match = res
                    used_indices.add(idx)
                    break

        if match is not None:
            filtered_results.append(match)

    return filtered_results


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND",
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not filter_specs:
        return search_results

    # Normalize and validate logic
    logic = (filter_logic or "AND").upper()
    if logic not in {"AND", "OR"}:
        raise ValueError(f"Unsupported filter_logic '{filter_logic}'. Use 'AND' or 'OR'.")

    # Convert SearchResult objects to dicts for the filter engine
    result_dicts = _results_to_dicts(search_results)

    # Initialize engine
    engine = MetadataFilterEngine()

    if logic == "AND":
        # The engine natively implements AND across all fields
        filtered_dicts = engine.apply_filters(result_dicts, filter_specs)
    else:
        # OR logic: keep results that satisfy at least one field's filter
        # We apply filters separately for each field specification and union the results.
        matched_ids = set()
        matched_dicts: List[Dict[str, Any]] = []

        for field_name, spec in filter_specs.items():
            if not spec:
                continue
            # Build a per-field filter spec
            single_filter = {field_name: spec}
            partial = engine.apply_filters(result_dicts, single_filter)

            for d in partial:
                d_id = d.get("id")
                key = (d_id, d.get("text"), d.get("score"))
                if key not in matched_ids:
                    matched_ids.add(key)
                    matched_dicts.append(d)

        filtered_dicts = matched_dicts

    # Convert back to SearchResult objects, preserving original instances
    return _dicts_to_results(search_results, filtered_dicts)

